const txn = $input.first().json.body || $input.first().json;

const watchlist = [
  {
    account_number: "DE89370400440532013000",
    entity_name: "XYZ Trading FZE",
    list_type: "OFAC_SDN",
    risk_level: "HIGH",
    match_reason: "OFAC Specially Designated Nationals list — UAE entity"
  },
  {
    account_number: "FR7630006000011234567890189",
    entity_name: "ABC Shell Corp",
    list_type: "UN_SANCTIONS",
    risk_level: "HIGH",
    match_reason: "UN Security Council sanctions list"
  },
  {
    account_number: "RU123456789012345",
    entity_name: "Ivan Petrov Holdings",
    list_type: "HMT_SANCTIONS",
    risk_level: "HIGH",
    match_reason: "UK HM Treasury sanctions — Russian entity"
  },
  {
    account_number: "IR987654321098765",
    entity_name: "Tehran Import Export",
    list_type: "OFAC_IRAN",
    risk_level: "HIGH",
    match_reason: "OFAC Iran sanctions programme"
  },
  {
    account_number: "GB12FAKE12345678901234",
    entity_name: "Fraud Merchant Ltd",
    list_type: "INTERNAL_FRAUD",
    risk_level: "MEDIUM",
    match_reason: "Internal fraud watchlist — previous chargeback history"
  }
];

// ✅ Fix operators too (remove HTML encoding)
const hits = watchlist.filter(w =>
  w.account_number === txn.sender_account ||
  w.account_number === txn.beneficiary_account ||
  (txn.beneficiary_name && txn.beneficiary_name.toLowerCase().includes(w.entity_name.toLowerCase())) ||
  (txn.sender_name && txn.sender_name.toLowerCase().includes(w.entity_name.toLowerCase()))
);

// ✅ FINAL OUTPUT — include everything
return [{
  json: {
    txn_data: txn,
    watchlist_hits: hits.length > 0 ? hits : [],
    db_hit: hits.length > 0,
    screening_timestamp: new Date().toISOString()
  }
}];

// Parse AI agent response
const rawOutput = $input.first().json.output || $input.first().json.text || '{}';

let aiDecision;
try {
  // Strip markdown code fences if present
  const cleaned = rawOutput.replace(/```json|```/g, '').trim();
  aiDecision = JSON.parse(cleaned);
} catch(e) {
  // Fallback if parsing fails
  aiDecision = {
    hit: true,
    risk_level: 'HIGH',
    reason: 'AI response parse error — defaulting to manual review',
    action: 'MANUAL_REVIEW',
    txn_ref: 'UNKNOWN',
    status: 'PENDING',
    screened_by: 'AI_COMPLIANCE_AGENT',
    aml_flags: ['PARSE_ERROR'],
    recommendation: 'Manual review required'
  };
}

// Add metadata
aiDecision.processed_at = new Date().toISOString();
aiDecision.workflow = 'AML_COMPLIANCE_SCREENING';

return [{ json: aiDecision }];

// =============================================
// MOCK DB UPDATE — Simulates writing back to DB
// In production: replace with real PostgreSQL node
// =============================================

const item = $input.first().json;

// Simulate DB update log
const dbUpdateLog = {
  table: 'payment_transactions',
  operation: 'UPDATE',
  txn_ref: item.txn_ref,
  fields_updated: {
    status: item.final_status,
    aml_action: item.final_action,
    aml_reason: item.reason,
    risk_level: item.risk_level,
    requires_manual_review: item.requires_manual_review,
    screened_at: item.decision_timestamp,
    screened_by: 'AI_COMPLIANCE_AGENT'
  },
  db_response: 'MOCK_SUCCESS',
  rows_affected: 1,
  timestamp: new Date().toISOString()
};

console.log('Mock DB Update:', JSON.stringify(dbUpdateLog, null, 2));

// Pass through all fields + db log
return [{ json: { ...item, db_update_log: dbUpdateLog } }];

// Build Excel row for compliance report
const item = $input.first().json;

const row = {
  TXN_REF: item.txn_ref || 'N/A',
  STATUS: item.final_status || 'UNKNOWN',
  RISK_LEVEL: item.risk_level || 'N/A',
  ACTION: item.final_action || 'N/A',
  REASON: item.reason || 'N/A',
  AML_FLAGS: Array.isArray(item.aml_flags) ? item.aml_flags.join(', ') : 'NONE',
  REQUIRES_MANUAL_REVIEW: item.requires_manual_review ? 'YES' : 'NO',
  QUEUE: item.queue || 'N/A',
  SCREENED_BY: 'AI_COMPLIANCE_AGENT',
  DECISION_TIMESTAMP: item.decision_timestamp || new Date().toISOString(),
  REPORT_GENERATED: new Date().toISOString()
};

return [{ json: row }];
